"use client";

import * as React from "react";
import {
  EditorTemplate,
  FileTree,
  Menubar,
  MenubarMenu,
  MenubarTrigger,
  MenubarContent,
  MenubarItem,
  MenubarSeparator,
  MenubarShortcut,
  Breadcrumb,
  BreadcrumbList,
  BreadcrumbItem,
  BreadcrumbPage,
  BreadcrumbSeparator,
  StatusBar,
  CodeBlock,
  Kbd,
  CollapsiblePanelToggle,
  Button,
  Badge,
  Separator,
  ScrollArea,
} from "@gunjo/ui";
import {
  IconX,
  IconGitBranch,
  IconBrandTypescript,
  IconCircleCheck,
  IconLayoutSidebar,
} from "@tabler/icons-react";
import { FILE_TREE, FILES, type OpenFile } from "./data";

const INITIAL_OPEN = ["src/app/page.tsx", "src/components/Editor.tsx"];

export default function EditorPage() {
  const [openIds, setOpenIds] = React.useState<string[]>(INITIAL_OPEN);
  const [activeId, setActiveId] = React.useState<string>("src/app/page.tsx");
  const [code, setCode] = React.useState<Record<string, string>>({});
  const [dirty, setDirty] = React.useState<Set<string>>(new Set());
  const [expanded, setExpanded] = React.useState<Set<string>>(
    new Set(["src", "src/app", "src/components"])
  );
  const [rightCollapsed, setRightCollapsed] = React.useState(false);
  const [leftCollapsed, setLeftCollapsed] = React.useState(false);
  const [cursor, setCursor] = React.useState({ line: 1, col: 1 });

  const active: OpenFile | undefined = FILES[activeId];
  const activeCode = active ? code[activeId] ?? active.code : "";

  function openFile(id: string) {
    if (!FILES[id]) return; // folder or unknown — ignore
    setOpenIds((ids) => (ids.includes(id) ? ids : [...ids, id]));
    setActiveId(id);
  }

  function closeTab(id: string, e?: React.MouseEvent) {
    e?.stopPropagation();
    setOpenIds((ids) => {
      const next = ids.filter((x) => x !== id);
      if (id === activeId && next.length) {
        setActiveId(next[Math.max(0, ids.indexOf(id) - 1)]);
      }
      return next;
    });
    setDirty((d) => {
      const n = new Set(d);
      n.delete(id);
      return n;
    });
  }

  function onCodeChange(next: string) {
    setCode((c) => ({ ...c, [activeId]: next }));
    setDirty((d) => new Set(d).add(activeId));
    const lines = next.split("\n");
    setCursor({ line: lines.length, col: (lines[lines.length - 1]?.length ?? 0) + 1 });
  }

  function save() {
    setDirty((d) => {
      const n = new Set(d);
      n.delete(activeId);
      return n;
    });
  }

  // Cmd/Ctrl+S to save
  React.useEffect(() => {
    function onKey(e: KeyboardEvent) {
      if ((e.metaKey || e.ctrlKey) && e.key.toLowerCase() === "s") {
        e.preventDefault();
        save();
      }
    }
    window.addEventListener("keydown", onKey);
    return () => window.removeEventListener("keydown", onKey);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [activeId]);

  /* ---------- Top bar: Menubar + toolbar + breadcrumb ---------- */
  const topBar = (
    <div className="flex w-full items-center gap-3 px-3 min-w-0">
      <Menubar className="border-0 bg-transparent p-0 shadow-none">
        {(["ファイル", "編集", "表示"] as const).map((label) => (
          <MenubarMenu key={label}>
            <MenubarTrigger>{label}</MenubarTrigger>
            <MenubarContent>
              <MenubarItem onSelect={() => openFile("README.md")}>
                README を開く
                <MenubarShortcut>⌘O</MenubarShortcut>
              </MenubarItem>
              <MenubarItem onSelect={save}>
                保存
                <MenubarShortcut>⌘S</MenubarShortcut>
              </MenubarItem>
              <MenubarSeparator />
              <MenubarItem onSelect={() => setLeftCollapsed((v) => !v)}>
                エクスプローラーを切り替え
              </MenubarItem>
              <MenubarItem onSelect={() => setRightCollapsed((v) => !v)}>
                アウトラインを切り替え
              </MenubarItem>
            </MenubarContent>
          </MenubarMenu>
        ))}
      </Menubar>

      <Separator orientation="vertical" className="h-5" />

      <Button
        variant="ghost"
        size="icon"
        aria-label="エクスプローラーを切り替え"
        onClick={() => setLeftCollapsed((v) => !v)}
        className="md:inline-flex"
      >
        <IconLayoutSidebar className="h-4 w-4" />
      </Button>

      {/* Breadcrumb path */}
      {active && (
        <Breadcrumb className="min-w-0">
          <BreadcrumbList className="flex-nowrap">
            {active.path.map((seg, i) => {
              const isLast = i === active.path.length - 1;
              return (
                <React.Fragment key={i}>
                  <BreadcrumbItem>
                    {isLast ? (
                      <BreadcrumbPage className="truncate">{seg}</BreadcrumbPage>
                    ) : (
                      <span className="truncate text-muted-foreground">{seg}</span>
                    )}
                  </BreadcrumbItem>
                  {!isLast && <BreadcrumbSeparator />}
                </React.Fragment>
              );
            })}
          </BreadcrumbList>
        </Breadcrumb>
      )}

      <div className="ml-auto flex items-center gap-2 shrink-0">
        <span className="hidden text-xs text-muted-foreground sm:inline">保存</span>
        <Kbd className="hidden sm:inline-flex">⌘S</Kbd>
        <Button size="sm" onClick={save} disabled={!dirty.has(activeId)}>
          保存
        </Button>
      </div>
    </div>
  );

  /* ---------- Left panel: file tree ---------- */
  const leftPanel = (
    <div className="flex h-full flex-col">
      <div className="flex h-9 items-center justify-between border-b px-3 text-xs font-semibold uppercase tracking-wide text-muted-foreground">
        エクスプローラー
      </div>
      <ScrollArea className="flex-1">
        <div className="p-2">
          <FileTree
            nodes={FILE_TREE}
            selectionMode="single"
            selectedIds={[activeId]}
            expanded={expanded}
            onExpandedChange={setExpanded}
            onNodeSelect={(node) => openFile(node.id)}
            renderNodeMeta={(node) =>
              dirty.has(node.id) ? (
                <span className="h-1.5 w-1.5 rounded-full bg-primary" aria-label="未保存" />
              ) : (
                node.size ?? null
              )
            }
          />
        </div>
      </ScrollArea>
    </div>
  );

  /* ---------- Right panel: outline ---------- */
  const rightPanel = (
    <div className="flex h-full flex-col">
      <div className="flex h-9 items-center justify-between border-b px-3 text-xs font-semibold uppercase tracking-wide text-muted-foreground">
        アウトライン
        <CollapsiblePanelToggle
          side="right"
          collapsed={false}
          onClick={() => setRightCollapsed(true)}
          className="h-7 w-7 shadow-none ring-0"
          closeLabel="アウトラインを折りたたむ"
        />
      </div>
      <ScrollArea className="flex-1">
        <ul className="p-2 text-sm">
          {active && active.outline.length > 0 ? (
            active.outline.map((sym) => (
              <li key={sym.name}>
                <button
                  type="button"
                  className="flex w-full items-center gap-2 rounded-md px-2 py-1.5 text-left hover:bg-muted"
                >
                  <Badge variant="secondary" className="text-[10px]">
                    {sym.kind}
                  </Badge>
                  <span className="truncate">{sym.name}</span>
                  <span className="ml-auto tabular-nums text-xs text-muted-foreground">
                    L{sym.line}
                  </span>
                </button>
              </li>
            ))
          ) : (
            <li className="px-2 py-4 text-center text-xs text-muted-foreground">
              シンボルなし
            </li>
          )}
        </ul>
      </ScrollArea>
    </div>
  );

  /* ---------- Center: tab strip + code area ---------- */
  const center = (
    <div className="flex h-full min-h-0 flex-col bg-background">
      {/* Tab strip */}
      <div
        role="tablist"
        aria-label="開いているファイル"
        className="flex h-10 shrink-0 items-stretch overflow-x-auto border-b bg-muted/30"
      >
        {openIds.map((id) => {
          const f = FILES[id];
          if (!f) return null;
          const isActive = id === activeId;
          return (
            <div
              key={id}
              role="tab"
              aria-selected={isActive}
              tabIndex={isActive ? 0 : -1}
              onClick={() => setActiveId(id)}
              onKeyDown={(e) => {
                if (e.key === "Enter" || e.key === " ") {
                  e.preventDefault();
                  setActiveId(id);
                } else if (e.key === "ArrowRight" || e.key === "ArrowLeft") {
                  e.preventDefault();
                  const dir = e.key === "ArrowRight" ? 1 : -1;
                  const idx = (openIds.indexOf(id) + dir + openIds.length) % openIds.length;
                  setActiveId(openIds[idx]);
                }
              }}
              className={[
                "group flex cursor-pointer items-center gap-2 border-r px-3 text-sm outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-inset",
                isActive
                  ? "bg-background text-foreground"
                  : "text-muted-foreground hover:bg-background/60",
              ].join(" ")}
            >
              <span className="truncate">{f.name}</span>
              {dirty.has(id) && <span className="h-1.5 w-1.5 rounded-full bg-primary" />}
              <button
                type="button"
                aria-label={`${f.name} を閉じる`}
                onClick={(e) => closeTab(id, e)}
                className="rounded p-0.5 opacity-60 hover:bg-muted hover:opacity-100"
              >
                <IconX className="h-3.5 w-3.5" />
              </button>
            </div>
          );
        })}
      </div>

      {/* Code area */}
      <div className="min-h-0 flex-1 overflow-auto">
        {active ? (
          <CodeBlock
            key={activeId}
            code={activeCode}
            language={active.language}
            showLineNumbers
            highlight
            editable
            onCodeChange={onCodeChange}
            copyable
            theme="dark"
            className="h-full rounded-none border-0"
          />
        ) : (
          <div className="flex h-full items-center justify-center text-sm text-muted-foreground">
            ファイルが開かれていません
          </div>
        )}
      </div>
    </div>
  );

  /* ---------- Status bar (non-fixed, inside the shell) ---------- */
  const statusBar = (
    <StatusBar
      fixed={false}
      className="w-full max-w-none rounded-none px-3 sm:flex-row"
      leftNode={
        <span className="flex items-center gap-1.5">
          <IconGitBranch className="h-3.5 w-3.5" /> main
        </span>
      }
      rightNode={
        <span className="flex items-center gap-3">
          <span className="flex items-center gap-1">
            <IconBrandTypescript className="h-3.5 w-3.5" />
            {active?.language ?? "—"}
          </span>
          <span className="flex items-center gap-1">
            <IconCircleCheck className="h-3.5 w-3.5" />
            {dirty.size === 0 ? "保存済み" : `未保存 ${dirty.size} 件`}
          </span>
        </span>
      }
    >
      <span className="tabular-nums">
        行 {cursor.line}, 列 {cursor.col}
      </span>
    </StatusBar>
  );

  return (
    <div className="flex h-[100dvh] flex-col">
      <EditorTemplate
        className="flex-1 min-h-0"
        topBar={topBar}
        leftPanel={leftCollapsed ? undefined : leftPanel}
        rightPanel={rightCollapsed ? undefined : rightPanel}
      >
        <div className="relative h-full">
          {center}
          {rightCollapsed && (
            <div className="absolute right-3 top-3 z-20 hidden lg:block">
              <CollapsiblePanelToggle
                side="right"
                collapsed
                onClick={() => setRightCollapsed(false)}
                openLabel="アウトラインを表示"
              />
            </div>
          )}
        </div>
      </EditorTemplate>
      {statusBar}
    </div>
  );
}

import type { FileTreeNode } from "@gunjo/ui";

export interface OpenFile {
  id: string;
  name: string;
  /** Breadcrumb segments for the path. */
  path: string[];
  language: string;
  code: string;
  /** Outline entries (symbol name + line). */
  outline: { name: string; kind: string; line: number }[];
}

export const FILE_TREE: FileTreeNode[] = [
  {
    id: "src",
    label: "src",
    type: "folder",
    children: [
      {
        id: "src/app",
        label: "app",
        type: "folder",
        children: [
          { id: "src/app/page.tsx", label: "page.tsx", type: "file", size: "2.1 KB" },
          { id: "src/app/layout.tsx", label: "layout.tsx", type: "file", size: "1.4 KB" },
        ],
      },
      {
        id: "src/components",
        label: "components",
        type: "folder",
        children: [
          { id: "src/components/Editor.tsx", label: "Editor.tsx", type: "file", size: "8.7 KB" },
          { id: "src/components/Sidebar.tsx", label: "Sidebar.tsx", type: "file", size: "3.2 KB" },
        ],
      },
      { id: "src/index.ts", label: "index.ts", type: "file", size: "412 B" },
    ],
  },
  {
    id: "public",
    label: "public",
    type: "folder",
    children: [{ id: "public/favicon.ico", label: "favicon.ico", type: "file", size: "15 KB" }],
  },
  { id: "package.json", label: "package.json", type: "file", size: "1.1 KB" },
  { id: "README.md", label: "README.md", type: "file", size: "640 B" },
];

export const FILES: Record<string, OpenFile> = {
  "src/app/page.tsx": {
    id: "src/app/page.tsx",
    name: "page.tsx",
    path: ["src", "app", "page.tsx"],
    language: "tsx",
    code: `import { Button } from "@gunjo/ui";

export default function Page() {
  const handleClick = () => {
    console.log("クリックされました");
  };

  return (
    <main className="p-8">
      <h1>ようこそ</h1>
      <Button onClick={handleClick}>はじめる</Button>
    </main>
  );
}
`,
    outline: [
      { name: "Page", kind: "function", line: 3 },
      { name: "handleClick", kind: "const", line: 4 },
    ],
  },
  "src/components/Editor.tsx": {
    id: "src/components/Editor.tsx",
    name: "Editor.tsx",
    path: ["src", "components", "Editor.tsx"],
    language: "tsx",
    code: `import * as React from "react";

export interface EditorProps {
  value: string;
  onChange: (next: string) => void;
}

export function Editor({ value, onChange }: EditorProps) {
  return (
    <textarea
      value={value}
      onChange={(e) => onChange(e.target.value)}
    />
  );
}
`,
    outline: [
      { name: "EditorProps", kind: "interface", line: 3 },
      { name: "Editor", kind: "function", line: 8 },
    ],
  },
  "src/index.ts": {
    id: "src/index.ts",
    name: "index.ts",
    path: ["src", "index.ts"],
    language: "ts",
    code: `export { Editor } from "./components/Editor";
export type { EditorProps } from "./components/Editor";
`,
    outline: [],
  },
  "README.md": {
    id: "README.md",
    name: "README.md",
    path: ["README.md"],
    language: "markdown",
    code: `# gunjo-test

@gunjo/ui で構築したデモ用 IDE シェルです。

## 起動方法

\`\`\`bash
npm run dev
\`\`\`
`,
    outline: [],
  },
};
